Javascript.validate:
			// Validation: Date cannot be in the future. Working day only.	
			
			var filingDate = Services.getValue(FilingDate.dataBinding);
			var err = null;

			if( true == isFutureDate(filingDate))
			{	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
			}
			else if( isNonWorkingDate(filingDate))
		    {   err = ErrorCode.getErrorCode("CaseMan_dateNonWorkingDay_Msg"); 
		    }

		    return err;
